UPDATE UNVEILING SET
CURRENT_PRICE = #{currentPrice},
BIDDING_COUNT = #{biddingCount},
UNVEILING_STATUS = #{unveilingStatus}
WHERE UNVEILING_NO =
#{unveilingNo}

UPDATE UNVEILING
SET FINISH_DATE = #{finishDate}
WHERE UNVEILING_NO = #{unveilingNo}

UPDATE UNVEILING
SET UNVEILING_STATUS = 'ENDED'
WHERE UNVEILING_NO = #{unveilingNo}
